import { watch } from 'vue'

import type { LGraph } from '@/lib/litegraph/src/LGraph'
import type { LGraphNode } from '@/lib/litegraph/src/litegraph'
import { app } from '@/scripts/app'
import { useNodeTypeColorStore } from '@/stores/nodeTypeColorStore'
import { applyNodeColorPair } from '@/utils/nodeColorApply'

const hookedGraphs = new WeakSet<LGraph>()

function applyStoredDefaultIfUnset(node: LGraphNode) {
  const store = useNodeTypeColorStore()
  const t = node.type
  if (!t) return
  const def = store.getTypeDefault(t)
  if (!def) return
  if (node.color !== undefined || node.bgcolor !== undefined) return
  applyNodeColorPair(node, def.color, def.bgcolor)
}

function hookGraph(graph: LGraph) {
  if (hookedGraphs.has(graph)) return
  hookedGraphs.add(graph)

  const prev = graph.onNodeAdded
  graph.onNodeAdded = function (this: LGraph, node: LGraphNode) {
    prev?.call(this, node)
    queueMicrotask(() => {
      if (node.graph !== graph) return
      applyStoredDefaultIfUnset(node)
    })
  }
}

app.registerExtension({
  name: 'Comfy.NodeTypeColorPalette',

  init() {
    watch(
      () => app.canvas?.graph,
      (g) => {
        if (g) hookGraph(g)
      },
      { immediate: true }
    )
  }
})
