/**
 * Hold Y and the canvas thinks you brought scissors. Cursor goes crosshair, you feel dangerous.
 * Drag a red dashed line through cables and they politely detach where the stroke crossed them.
 * Release Y to sheathe the blades; if you let go of Y mid drag we abort the cut because panic
 * clicks happen. Hit testing reuses wireHitTest.ts so we stay friends with wire selection.
 */

import type { Rectangle } from '@/lib/litegraph/src/litegraph'
import { useToastStore } from '@/platform/updates/common/toastStore'
import { app } from '@/scripts/app'
import {
  findLinkIdsForCutLine,
  graphCoordsFromPointer,
  removeLinksByIds
} from './wireHitTest'

const MIN_CUT_LENGTH = 4

let scissorsMode = false
let cutting = false
let cutStart: [number, number] | null = null
let cutEnd: [number, number] | null = null
let activeCutPointerId: number | null = null

function drawCutPreview(
  ctx: CanvasRenderingContext2D,
  _visibleArea: Rectangle
) {
  if (!cutting || !cutStart || !cutEnd) return
  const scale = app.canvas.ds.scale
  ctx.save()
  ctx.strokeStyle = '#e94242'
  ctx.lineWidth = 2 / scale
  ctx.setLineDash([8 / scale, 5 / scale])
  ctx.beginPath()
  ctx.moveTo(cutStart[0], cutStart[1])
  ctx.lineTo(cutEnd[0], cutEnd[1])
  ctx.stroke()
  ctx.restore()
}

function setScissorsCursor(on: boolean) {
  app.canvasEl.style.cursor = on ? 'crosshair' : ''
}

function cancelCutGesture(canvas: typeof app.canvas) {
  if (!cutting) return
  cutting = false
  cutStart = null
  cutEnd = null
  if (activeCutPointerId != null) {
    try {
      app.canvasEl.releasePointerCapture(activeCutPointerId)
    } catch {
      /* ignore */
    }
    activeCutPointerId = null
  }
  canvas.setDirty(false, true)
}

function isYKey(e: KeyboardEvent): boolean {
  return e.key === 'y' || e.key === 'Y'
}

app.registerExtension({
  name: 'Comfy.HoudiniWireInteraction',

  init() {
    const canvas = app.canvas
    const el = app.canvasEl

    const originalDrawForeground = canvas.onDrawForeground
    canvas.onDrawForeground = function (
      ctx: CanvasRenderingContext2D,
      visibleArea: Rectangle
    ) {
      originalDrawForeground?.call(this, ctx, visibleArea)
      drawCutPreview(ctx, visibleArea)
    }

    window.addEventListener(
      'keydown',
      (e: KeyboardEvent) => {
        const target = e.target as HTMLElement | null
        if (target?.closest?.('input, textarea, [contenteditable="true"]')) return

        if (e.repeat) return

        if (isYKey(e)) {
          scissorsMode = true
          setScissorsCursor(true)
        }
      },
      true
    )

    window.addEventListener(
      'keyup',
      (e: KeyboardEvent) => {
        const target = e.target as HTMLElement | null
        if (target?.closest?.('input, textarea, [contenteditable="true"]')) return

        if (isYKey(e)) {
          scissorsMode = false
          setScissorsCursor(false)
          cancelCutGesture(canvas)
        }
      },
      true
    )

    window.addEventListener('blur', () => {
      if (!scissorsMode && !cutting) return
      scissorsMode = false
      setScissorsCursor(false)
      cancelCutGesture(canvas)
    })

    el.addEventListener(
      'pointerdown',
      (e: PointerEvent) => {
        if (!scissorsMode || e.button !== 0) return
        cutting = true
        cutStart = graphCoordsFromPointer(e)
        cutEnd = [...cutStart] as [number, number]
        activeCutPointerId = e.pointerId
        try {
          el.setPointerCapture(e.pointerId)
        } catch {
          /* ignore */
        }
        e.preventDefault()
        e.stopImmediatePropagation()
        canvas.setDirty(false, true)
      },
      true
    )

    el.addEventListener(
      'pointermove',
      (e: PointerEvent) => {
        if (!cutting || !cutStart) return
        cutEnd = graphCoordsFromPointer(e)
        e.preventDefault()
        e.stopImmediatePropagation()
        canvas.setDirty(false, true)
      },
      true
    )

    const finishCut = (e: PointerEvent) => {
      if (!cutting || !cutStart || !cutEnd) return
      if (activeCutPointerId != null && e.pointerId !== activeCutPointerId) return

      cutting = false
      const end = graphCoordsFromPointer(e)
      cutEnd = end

      try {
        el.releasePointerCapture(e.pointerId)
      } catch {
        /* ignore */
      }
      activeCutPointerId = null

      const dx = cutEnd[0] - cutStart[0]
      const dy = cutEnd[1] - cutStart[1]
      const len = Math.hypot(dx, dy)
      const start = cutStart
      const finish = cutEnd
      cutStart = null
      cutEnd = null

      e.preventDefault()
      e.stopImmediatePropagation()

      if (!scissorsMode) {
        canvas.setDirty(false, true)
        return
      }

      if (len >= MIN_CUT_LENGTH) {
        const ids = findLinkIdsForCutLine(
          start[0],
          start[1],
          finish[0],
          finish[1]
        )
        if (ids.size > 0) {
          removeLinksByIds(ids)
          useToastStore().add({
            severity: 'success',
            summary: 'Wires cut',
            detail: `${ids.size} connection(s) removed.`,
            life: 2200
          })
        }
      }

      canvas.setDirty(false, true)
    }

    el.addEventListener('pointerup', finishCut, true)
    el.addEventListener('pointercancel', finishCut, true)
  }
})
