/**
 * Experimental node assist lives under Settings, Comfy, Experimental, NodeAssist.
 *
 * Absolute overlap avoidance shoves polite nodes aside when you drop or drag something grumpy
 * on top of them. Toggle lives in settings; it is on by default because stacks of identical
 * KSamplers help nobody. Auto layout itself is not here; press L for Comfy.Canvas.LayoutGraph
 * and read experimentalGraphLayout.ts if you crave the math bedtime story.
 */

import { watch } from 'vue'

import type { LGraph } from '@/lib/litegraph/src/LGraph'
import type { LGraphCanvas } from '@/lib/litegraph/src/LGraphCanvas'
import type { ReadOnlyRectangle } from '@/lib/litegraph/src/infrastructure/Rectangle'
import type { LGraphTriggerEvent } from '@/lib/litegraph/src/types/graphTriggers'
import { LGraphNode } from '@/lib/litegraph/src/LGraphNode'
import { getAllNestedItems } from '@/lib/litegraph/src/utils/collections'
import { useSettingStore } from '@/platform/settings/settingStore'
import { useWorkflowStore } from '@/platform/workflow/management/stores/workflowStore'
import { app } from '@/scripts/app'

const hookedGraphs = new WeakSet<LGraph>()

const OVERLAP_MARGIN = 6
const MAX_OVERLAP_ITERS = 64

function rectOverlap(
  a: ReadOnlyRectangle,
  b: ReadOnlyRectangle,
  margin: number
): boolean {
  const ax1 = a[0] - margin * 0.5
  const ay1 = a[1] - margin * 0.5
  const ax2 = a[0] + a[2] + margin * 0.5
  const ay2 = a[1] + a[3] + margin * 0.5
  const bx1 = b[0] - margin * 0.5
  const by1 = b[1] - margin * 0.5
  const bx2 = b[0] + b[2] + margin * 0.5
  const by2 = b[1] + b[3] + margin * 0.5
  return ax1 < bx2 && ax2 > bx1 && ay1 < by2 && ay2 > by1
}

/** Smallest shove that stops B from sitting on A's lap. */
function pushBFromA(
  a: ReadOnlyRectangle,
  b: ReadOnlyRectangle,
  margin: number
): [number, number] {
  const ax1 = a[0]
  const ay1 = a[1]
  const ax2 = a[0] + a[2]
  const ay2 = a[1] + a[3]
  const bx1 = b[0]
  const by1 = b[1]
  const bx2 = b[0] + b[2]
  const by2 = b[1] + b[3]
  const ox = Math.min(ax2, bx2) - Math.max(ax1, bx1)
  const oy = Math.min(ay2, by2) - Math.max(ay1, by1)
  if (ox <= 0 || oy <= 0) return [0, 0]

  const cxA = (ax1 + ax2) * 0.5
  const cyA = (ay1 + ay2) * 0.5
  const cxB = (bx1 + bx2) * 0.5
  const cyB = (by1 + by2) * 0.5
  const extra = margin

  if (ox < oy) {
    return cxB < cxA ? [-(ox + extra), 0] : [ox + extra, 0]
  }
  return cyB < cyA ? [0, -(oy + extra)] : [0, oy + extra]
}

function collectAnchorNodes(
  canvas: LGraphCanvas,
  primary: LGraphNode | undefined
): LGraphNode[] {
  const nested = getAllNestedItems(canvas.selectedItems)
  const fromSelection = [...nested].filter(
    (item): item is LGraphNode =>
      item instanceof LGraphNode && !item.flags?.ghost
  )
  if (fromSelection.length) return fromSelection
  if (primary && !primary.flags?.ghost) return [primary]
  return []
}

/**
 * Anchors are sacred ground. Everyone else gets bounced off them, then we break up fights
 * between the remaining movable nodes until the graph stops looking like a rugby scrum.
 */
function resolveOverlapsWithAnchors(
  anchors: LGraphNode[],
  graph: LGraph
): void {
  if (!anchors.length) return
  const anchorSet = new Set(anchors)

  for (let iter = 0; iter < MAX_OVERLAP_ITERS; iter++) {
    let changed = false

    for (const n of graph._nodes) {
      if (anchorSet.has(n) || n.flags?.ghost) continue
      try {
        n.updateArea()
      } catch {
        /* ignore */
      }
      const nr = n.boundingRect

      for (const a of anchors) {
        if (a.flags?.ghost) continue
        try {
          a.updateArea()
        } catch {
          /* ignore */
        }
        const ar = a.boundingRect
        if (!rectOverlap(ar, nr, 0)) continue
        const [dx, dy] = pushBFromA(ar, nr, OVERLAP_MARGIN)
        if (dx !== 0 || dy !== 0) {
          n.pos[0] += dx
          n.pos[1] += dy
          changed = true
        }
      }
    }

    const movable = graph._nodes.filter(
      (n) => !anchorSet.has(n) && !n.flags?.ghost
    )
    for (let i = 0; i < movable.length; i++) {
      for (let j = i + 1; j < movable.length; j++) {
        const a = movable[i]
        const b = movable[j]
        try {
          a.updateArea()
          b.updateArea()
        } catch {
          /* ignore */
        }
        const ar = a.boundingRect
        const br = b.boundingRect
        if (!rectOverlap(ar, br, 0)) continue
        const [dx, dy] = pushBFromA(ar, br, OVERLAP_MARGIN)
        if (dx === 0 && dy === 0) continue
        if (b.id > a.id) {
          b.pos[0] += dx
          b.pos[1] += dy
        } else {
          a.pos[0] += dx
          a.pos[1] += dy
        }
        changed = true
      }
    }

    if (!changed) break
  }
}

function runOverlapAvoidance(
  canvas: LGraphCanvas,
  graph: LGraph,
  anchors: LGraphNode[]
): void {
  if (!anchors.length) return
  graph.beforeChange()
  try {
    resolveOverlapsWithAnchors(anchors, graph)
  } finally {
    graph.afterChange()
  }
  canvas.setDirty(true, true)
  useWorkflowStore().activeWorkflow?.changeTracker?.checkState()
}

function scheduleForNewNode(node: LGraphNode): void {
  if (!useSettingStore().get('Comfy.Experimental.AbsoluteOverlapAvoidance')) return
  const canvas = app.canvas
  const graph = canvas.graph
  if (!graph || canvas.read_only) return
  if (node.graph !== graph) return
  if (node.isVirtualNode) return
  if (node.flags?.ghost) return

  queueMicrotask(() => {
    if (!useSettingStore().get('Comfy.Experimental.AbsoluteOverlapAvoidance')) return
    if (!node.graph || node.flags?.ghost) return
    runOverlapAvoidance(canvas, graph, [node])
  })
}

function hookGraph(graph: LGraph, canvas: LGraphCanvas) {
  if (hookedGraphs.has(graph)) return
  hookedGraphs.add(graph)

  const prevOnAdded = graph.onNodeAdded
  graph.onNodeAdded = function (this: LGraph, node: LGraphNode) {
    prevOnAdded?.call(this, node)
    if (node.flags?.ghost) return
    scheduleForNewNode(node)
  }

  const prevTrigger = graph.onTrigger
  graph.onTrigger = function (this: LGraph, e: LGraphTriggerEvent) {
    prevTrigger?.call(this, e)
    if (e.type !== 'node:property:changed') return
    if (e.property !== 'flags.ghost' || e.newValue !== false) return
    const n = graph.getNodeById(e.nodeId)
    if (!n) return
    scheduleForNewNode(n)
  }

  const prevOnMoved = canvas.onNodeMoved
  canvas.onNodeMoved = (node: LGraphNode | undefined) => {
    prevOnMoved?.(node)
    if (!useSettingStore().get('Comfy.Experimental.AbsoluteOverlapAvoidance')) return
    if (canvas.read_only) return
    const anchors = collectAnchorNodes(canvas, node)
    if (!anchors.length) return
    runOverlapAvoidance(canvas, graph, anchors)
  }
}

app.registerExtension({
  name: 'Comfy.ExperimentalNodeAssist',

  init() {
    watch(
      () => app.canvas?.graph,
      (g) => {
        if (g && app.canvas) hookGraph(g, app.canvas)
      },
      { immediate: true }
    )
  }
})
