/**
 * Fancy cable social life: hover glows orange, ctrl click toggles membership in the cool kids
 * club, shift ctrl click on a link adds on release so you can hoard wires like trading cards.
 *
 * Ctrl drag on empty canvas is still classic LiteGraph node boxing; we do not steal that.
 * Ctrl alt drag paints a green marquee over the graph and scoops every link the rectangle
 * kisses. On release, shift replaces the whole wire selection with that haul, plain alt without
 * ctrl subtracts the box from the set, and alt with ctrl still means add so you do not nuke
 * everything by accident.
 *
 * Ctrl click on empty canvas is deliberately boring and leaves wire selection alone. A normal
 * left click on empty background clears only link picks, not your nodes. Delete or backspace
 * deletes selected wires, escape clears the wire set, and picking nodes forgets the wire party
 * because priorities exist.
 */

import type { Rectangle } from '@/lib/litegraph/src/litegraph'
import { LiteGraph } from '@/lib/litegraph/src/litegraph'
import { LLink } from '@/lib/litegraph/src/LLink'
import { Reroute } from '@/lib/litegraph/src/Reroute'
import type { Bounds } from '@/renderer/core/layout/types'
import { layoutStore } from '@/renderer/core/layout/store/layoutStore'
import { app } from '@/scripts/app'

import {
  findLinkIdsForCutLine,
  graphCoordsFromPointer,
  removeLinksByIds
} from './wireHitTest'

const MARQUEE_DRAG_PX = 5

let hoverLinkIds = new Set<number>()
let selectedLinkIds = new Set<number>()
let wireMarquee: { x1: number; y1: number; x2: number; y2: number } | null =
  null
let wirePointerSession = false

function normalizeBounds(
  x1: number,
  y1: number,
  x2: number,
  y2: number
): Bounds {
  const x = Math.min(x1, x2)
  const y = Math.min(y1, y2)
  const width = Math.max(Math.abs(x2 - x1), 1)
  const height = Math.max(Math.abs(y2 - y1), 1)
  return { x, y, width, height }
}

function applyMarqueeToLinkSelection(
  picked: number[],
  shift: boolean,
  alt: boolean
): void {
  if (alt) {
    for (const id of picked) selectedLinkIds.delete(id)
    return
  }
  if (picked.length === 0) return
  if (shift) {
    selectedLinkIds.clear()
    for (const id of picked) selectedLinkIds.add(id)
    return
  }
  for (const id of picked) selectedLinkIds.add(id)
}

/**
 * When layoutStore plays hide and seek, we brute force the rectangle with the same stroke
 * sampling scissors use, edges and interior dots, so nothing slips through.
 */
function collectLinkIdsInRectByStrokeScan(b: Bounds): number[] {
  const ids = new Set<number>()
  const x0 = b.x
  const y0 = b.y
  const x1 = b.x + b.width
  const y1 = b.y + b.height
  const mx = (x0 + x1) * 0.5
  const my = (y0 + y1) * 0.5
  const addLine = (xa: number, ya: number, xb: number, yb: number) => {
    for (const id of findLinkIdsForCutLine(xa, ya, xb, yb)) ids.add(id)
  }
  addLine(x0, y0, x1, y0)
  addLine(x1, y0, x1, y1)
  addLine(x1, y1, x0, y1)
  addLine(x0, y1, x0, y0)
  addLine(x0, y0, x1, y1)
  addLine(x1, y0, x0, y1)
  addLine(x0, my, x1, my)
  addLine(mx, y0, mx, y1)
  const step = Math.max(28, Math.min(b.width, b.height) / 6)
  for (let x = x0; x <= x1; x += step) {
    for (let y = y0; y <= y1; y += step) {
      for (const id of findLinkIdsForCutLine(x, y, x, y)) ids.add(id)
    }
  }
  return Array.from(ids)
}

function startWirePointerSession(
  e: PointerEvent,
  idsAtDown: Set<number>
): void {
  wirePointerSession = true
  const [sx, sy] = graphCoordsFromPointer(e)
  let cx = sx
  let cy = sy
  let dragMarquee = false
  const ptr = e.pointerId
  const shiftAtDown = e.shiftKey

  const onMove = (ev: PointerEvent) => {
    if (ev.pointerId !== ptr) return
    const [mx, my] = graphCoordsFromPointer(ev)
    cx = mx
    cy = my
    if (Math.hypot(cx - sx, cy - sy) > MARQUEE_DRAG_PX) {
      dragMarquee = true
      wireMarquee = { x1: sx, y1: sy, x2: cx, y2: cy }
    }
    app.canvas.setDirty(false, true)
  }

  const finish = (ev: PointerEvent) => {
    if (ev.pointerId !== ptr) return
    window.removeEventListener('pointermove', onMove, true)
    window.removeEventListener('pointerup', finish, true)
    window.removeEventListener('pointercancel', finish, true)

    const [ux, uy] = graphCoordsFromPointer(ev)
    cx = ux
    cy = uy

    wireMarquee = null
    wirePointerSession = false

    if (dragMarquee) {
      const b = normalizeBounds(sx, sy, cx, cy)
      const { links: fromLayout } = layoutStore.queryItemsInBounds(b)
      const graph = app.canvas.graph
      if (graph) {
        const fromScan = collectLinkIdsInRectByStrokeScan(b)
        const merged = new Set<number>()
        for (const id of fromLayout) {
          if (graph._links.has(id)) merged.add(id)
        }
        for (const id of fromScan) {
          if (graph._links.has(id)) merged.add(id)
        }
        // Alt still down after ctrl alt marquee means keep stuff. Subtract mode needs alt
        // without ctrl so we never read the gesture as rip this box out by mistake.
        applyMarqueeToLinkSelection(
          Array.from(merged),
          ev.shiftKey,
          ev.altKey && !ev.ctrlKey
        )
      }
    } else if (idsAtDown.size > 0) {
      if (shiftAtDown) {
        for (const id of idsAtDown) selectedLinkIds.add(id)
      } else {
        for (const id of idsAtDown) {
          if (selectedLinkIds.has(id)) selectedLinkIds.delete(id)
          else selectedLinkIds.add(id)
        }
      }
    }

    app.canvas.setDirty(false, true)
  }

  window.addEventListener('pointermove', onMove, true)
  window.addEventListener('pointerup', finish, true)
  window.addEventListener('pointercancel', finish, true)
}

function handleWireOnMouse(e: PointerEvent): boolean {
  if (e.button !== 0) return false
  const ctrlOrMeta = e.ctrlKey || e.metaKey
  if (!ctrlOrMeta) return false

  const canvas = app.canvas
  const graph = canvas.graph
  if (!graph || canvas.read_only) return false

  const [x, y] = graphCoordsFromPointer(e)

  const altHeld = e.altKey || e.getModifierState?.('Alt') === true

  /** If a wire is under the finger, ctrl drag starts from that cable instead of empty space. */
  const atPoint = findLinkIdsForCutLine(x, y, x, y)
  if (atPoint.size > 0) {
    startWirePointerSession(e, atPoint)
    return true
  }

  /** Ctrl alt marquee must win before Vue slots or subgraph IO eat the event for breakfast. */
  if (altHeld) {
    startWirePointerSession(e, new Set())
    return true
  }

  if (LiteGraph.vueNodesMode && layoutStore.querySlotAtPoint({ x, y })) {
    return false
  }

  const sub = canvas.subgraph
  if (sub) {
    if (
      sub.inputNode.containsPoint([x, y]) ||
      sub.outputNode.containsPoint([x, y])
    ) {
      return false
    }
  }

  const node = graph.getNodeOnPos(x, y, canvas.visible_nodes)
  if (node) return false

  return false
}

function drawWireSelectionOverlay(
  ctx: CanvasRenderingContext2D,
  _visibleArea: Rectangle
) {
  const canvas = app.canvas
  const scale = canvas.ds.scale

  if (wireMarquee) {
    const { x1, y1, x2, y2 } = wireMarquee
    const x = Math.min(x1, x2)
    const y = Math.min(y1, y2)
    const w = Math.abs(x2 - x1)
    const h = Math.abs(y2 - y1)
    ctx.save()
    ctx.strokeStyle = 'rgba(45, 160, 85, 0.95)'
    ctx.fillStyle = 'rgba(45, 160, 85, 0.12)'
    ctx.lineWidth = 1 / scale
    ctx.setLineDash([6 / scale, 4 / scale])
    ctx.fillRect(x, y, w, h)
    ctx.strokeRect(x, y, w, h)
    ctx.restore()
  }

  const showHover = hoverLinkIds.size > 0 && !wirePointerSession
  if (
    !showHover &&
    selectedLinkIds.size === 0
  ) {
    return
  }

  const drawnReroute = new Set<number>()

  ctx.save()
  ctx.lineJoin = 'round'
  ctx.lineCap = 'round'

  for (const seg of canvas.renderedPaths) {
    if (!seg.path) continue

    let highlight: 'none' | 'hover' | 'selected' = 'none'

    if (seg instanceof LLink) {
      const id = Number(seg.id)
      if (selectedLinkIds.has(id)) highlight = 'selected'
      else if (showHover && hoverLinkIds.has(id)) highlight = 'hover'
    } else if (seg instanceof Reroute) {
      const rid = Number(seg.id)
      for (const lid of seg.linkIds) {
        if (selectedLinkIds.has(lid)) {
          highlight = 'selected'
          break
        }
        if (showHover && hoverLinkIds.has(lid)) highlight = 'hover'
      }
      if (highlight !== 'none') {
        if (drawnReroute.has(rid)) continue
        drawnReroute.add(rid)
      }
    }

    if (highlight === 'none') continue

    ctx.strokeStyle =
      highlight === 'selected'
        ? 'rgba(255, 255, 255, 0.95)'
        : 'rgba(255, 200, 90, 0.9)'
    ctx.lineWidth = (highlight === 'selected' ? 5 : 3.5) / scale
    ctx.stroke(seg.path)
  }

  ctx.restore()
}

app.registerExtension({
  name: 'Comfy.WireSelectionInteraction',

  init() {
    const canvas = app.canvas
    const el = app.canvasEl

    /** Capture early so LiteGraph does not run off with the pointer before we decide. */
    const isGraphSurfaceTarget = (target: EventTarget | null): boolean => {
      if (!(target instanceof Node)) return false
      if (el === target || el.contains(target)) return true
      const overlay = canvas.overlayCanvas
      if (overlay && (overlay === target || overlay.contains(target))) return true
      return false
    }

    const onDocumentPointerDownCapture = (e: PointerEvent) => {
      if (e.button !== 0) return
      if (!(e.ctrlKey || e.metaKey)) return
      if (!isGraphSurfaceTarget(e.target)) return

      if (handleWireOnMouse(e)) {
        e.preventDefault()
        e.stopImmediatePropagation()
      }
    }
    document.addEventListener('pointerdown', onDocumentPointerDownCapture, true)

    const prevOnDraw = canvas.onDrawForeground
    canvas.onDrawForeground = function (
      ctx: CanvasRenderingContext2D,
      visibleArea: Rectangle
    ) {
      prevOnDraw?.call(this, ctx, visibleArea)
      drawWireSelectionOverlay(ctx, visibleArea)
    }

    const prevSelectionChange = canvas.onSelectionChange
    canvas.onSelectionChange = function (this: unknown, nodes) {
      if (canvas.selectedItems.size > 0) {
        selectedLinkIds.clear()
        canvas.setDirty(false, true)
      }
      prevSelectionChange?.call(this, nodes)
    }

    const updateHover = (e: PointerEvent) => {
      if (e.pointerType === 'pen' && e.buttons === 0) return
      if (wirePointerSession || canvas.read_only) return
      const [gx, gy] = graphCoordsFromPointer(e)
      const next = findLinkIdsForCutLine(gx, gy, gx, gy)
      let changed = next.size !== hoverLinkIds.size
      if (!changed) {
        for (const id of next) {
          if (!hoverLinkIds.has(id)) {
            changed = true
            break
          }
        }
        if (!changed) {
          for (const id of hoverLinkIds) {
            if (!next.has(id)) {
              changed = true
              break
            }
          }
        }
      }
      if (!changed) return
      hoverLinkIds = next
      canvas.setDirty(false, true)
    }

    el.addEventListener('pointermove', updateHover, { passive: true })

    /** Plain click on empty canvas clears wire picks; ctrl misses intentionally keep them. */
    el.addEventListener(
      'pointerdown',
      (e: PointerEvent) => {
        if (e.button !== 0) return
        if (e.ctrlKey || e.metaKey) return
        if (canvas.read_only) return
        const t = e.target as HTMLElement | null
        if (t?.closest?.('input, textarea, [contenteditable="true"]')) return

        const [gx, gy] = graphCoordsFromPointer(e)
        if (findLinkIdsForCutLine(gx, gy, gx, gy).size > 0) return
        const g = canvas.graph
        if (!g) return
        if (g.getNodeOnPos(gx, gy, canvas.visible_nodes)) return
        const sg = canvas.subgraph
        if (
          sg &&
          (sg.inputNode.containsPoint([gx, gy]) ||
            sg.outputNode.containsPoint([gx, gy]))
        ) {
          return
        }
        if (LiteGraph.vueNodesMode && layoutStore.querySlotAtPoint({ x: gx, y: gy }))
          return

        if (selectedLinkIds.size > 0) {
          selectedLinkIds.clear()
          canvas.setDirty(false, true)
        }
      },
      true
    )

    window.addEventListener(
      'keydown',
      (e: KeyboardEvent) => {
        const target = e.target as HTMLElement | null
        if (target?.closest?.('input, textarea, [contenteditable="true"]'))
          return

        if (e.key === 'Escape') {
          if (selectedLinkIds.size === 0) return
          selectedLinkIds.clear()
          canvas.setDirty(false, true)
          return
        }

        if (e.key !== 'Delete' && e.key !== 'Backspace') return
        if (selectedLinkIds.size === 0) return

        e.preventDefault()
        e.stopPropagation()
        removeLinksByIds(new Set(selectedLinkIds))
        selectedLinkIds.clear()
        canvas.setDirty(false, true)
      },
      true
    )
  }
})
