/**
 * One stop shop for “did we poke a cable” math. Scissors, selection, and future drama all
 * import from here so we do not maintain three slightly wrong copies. Graph comes from the
 * live canvas (root or subgraph), not a stale snapshot of app.graph, because ghosts deserve
 * accurate hit tests too.
 */

import type { Point } from '@/lib/litegraph/src/interfaces'
import { LGraphCanvas, LiteGraph } from '@/lib/litegraph/src/litegraph'
import { LLink } from '@/lib/litegraph/src/LLink'
import { Reroute } from '@/lib/litegraph/src/Reroute'
import { LinkDirection } from '@/lib/litegraph/src/types/globalEnums'
import { getSlotPosition } from '@/renderer/core/canvas/litegraph/slotCalculations'
import type { LinkRenderContext } from '@/renderer/core/canvas/litegraph/litegraphLinkAdapter'
import { layoutStore } from '@/renderer/core/layout/store/layoutStore'
import { useWorkflowStore } from '@/platform/workflow/management/stores/workflowStore'
import { app } from '@/scripts/app'

const CUT_LINE_SAMPLES = 80

export function graphCoordsFromPointer(e: PointerEvent): [number, number] {
  const c = app.canvas
  const rect = c.canvas.getBoundingClientRect()
  const clientX_rel = e.clientX - rect.left
  const clientY_rel = e.clientY - rect.top
  const x = clientX_rel / c.ds.scale - c.ds.offset[0]
  const y = clientY_rel / c.ds.scale - c.ds.offset[1]
  return [x, y]
}

function graphPointToHitTestBitmap(
  canvas: LGraphCanvas,
  gx: number,
  gy: number
): [number, number] {
  const dpr = Math.max(window.devicePixelRatio ?? 1, 1)
  const [cx, cy] = canvas.ds.convertOffsetToCanvas([gx, gy])
  return [cx * dpr, cy * dpr]
}

function isPointOnRenderedLinkPath(
  canvas: LGraphCanvas,
  path: Path2D,
  gx: number,
  gy: number
): boolean {
  const dpr = Math.max(window.devicePixelRatio ?? 1, 1)
  const [bx, by] = graphPointToHitTestBitmap(canvas, gx, gy)
  const lw = canvas.connections_width + 10

  const ctx = canvas.ctx
  ctx.save()
  try {
    ctx.setTransform(1, 0, 0, 1, 0, 0)
    ctx.lineWidth = lw
    if (ctx.isPointInStroke(path, gx, gy)) return true
  } finally {
    ctx.restore()
  }

  const bg = canvas.bgctx
  if (bg) {
    bg.save()
    try {
      bg.setTransform(dpr, 0, 0, dpr, 0, 0)
      canvas.ds.toCanvasContext(bg)
      bg.lineWidth = lw
      if (bg.isPointInStroke(path, bx, by)) return true
    } finally {
      bg.restore()
    }
  }

  ctx.save()
  try {
    ctx.lineWidth = lw
    if (ctx.isPointInStroke(path, gx * dpr, gy * dpr)) return true
  } finally {
    ctx.restore()
  }

  return false
}

function lineHitsPath(
  canvas: LGraphCanvas,
  path: Path2D,
  x1: number,
  y1: number,
  x2: number,
  y2: number
): boolean {
  for (let i = 0; i <= CUT_LINE_SAMPLES; i++) {
    const t = i / CUT_LINE_SAMPLES
    const px = x1 + (x2 - x1) * t
    const py = y1 + (y2 - y1) * t
    if (isPointOnRenderedLinkPath(canvas, path, px, py)) return true
  }
  return false
}

function buildAdapterLinkRenderContext(canvas: LGraphCanvas): LinkRenderContext {
  const c = canvas as unknown as { _pattern?: CanvasPattern | null }
  return {
    renderMode: canvas.links_render_mode,
    connectionWidth: canvas.connections_width,
    renderBorder: canvas.render_connections_border,
    lowQuality: canvas.low_quality,
    highQualityRender: canvas.highquality_render,
    scale: canvas.ds.scale,
    linkMarkerShape: canvas.linkMarkerShape,
    renderConnectionArrows: canvas.render_connection_arrows,
    highlightedLinks: new Set(Object.keys(canvas.highlighted_links)),
    defaultLinkColor: canvas.default_link_color,
    linkTypeColors: LGraphCanvas.link_type_colors,
    disabledPattern: c._pattern ?? null,
    linkLaneSpread: canvas.linkLaneSpread
  }
}

function collectCutIdsFromRebuiltSimpleLinks(
  canvas: LGraphCanvas,
  x1: number,
  y1: number,
  x2: number,
  y2: number
): Set<number> {
  const ids = new Set<number>()
  const graph = canvas.graph
  const adapter = canvas.linkRenderer
  if (!graph || !adapter) return ids

  const off = document.createElement('canvas')
  off.width = 8
  off.height = 8
  const octx = off.getContext('2d')
  if (!octx) return ids

  const renderCtx = buildAdapterLinkRenderContext(canvas)

  const testLink = (
    link: LLink,
    startPos: Point,
    endPos: Point,
    a: LinkDirection,
    b: LinkDirection
  ) => {
    if (LLink.getReroutes(graph, link).length > 0) return
    adapter.renderLinkDirect(
      octx,
      startPos,
      endPos,
      link,
      true,
      0,
      null,
      a,
      b,
      renderCtx,
      {}
    )
    const p = link.path
    if (p && lineHitsPath(canvas, p, x1, y1, x2, y2)) ids.add(link.id)
  }

  for (const node of graph._nodes) {
    const inputs = node.inputs
    if (!inputs?.length) continue
    for (let i = 0; i < inputs.length; i++) {
      const input = inputs[i]
      if (!input || input.link == null) continue
      const link = graph._links.get(input.link)
      if (!link) continue

      const endPos = LiteGraph.vueNodesMode
        ? getSlotPosition(node, i, true)
        : node.getInputPos(i)
      const start_node = graph.getNodeById(link.origin_id)
      if (!start_node) continue
      const outputId = link.origin_slot
      const startPos: Point =
        outputId === -1
          ? [start_node.pos[0] + 10, start_node.pos[1] + 10]
          : LiteGraph.vueNodesMode
            ? getSlotPosition(start_node, outputId, false)
            : start_node.getOutputPos(outputId)
      const output = start_node.outputs[outputId]
      if (!output) continue

      testLink(
        link,
        startPos,
        endPos,
        output.dir ?? LinkDirection.RIGHT,
        input.dir ?? LinkDirection.LEFT
      )
    }
  }

  const subgraph = canvas.subgraph
  if (subgraph) {
    for (const outSlot of subgraph.inputNode.slots) {
      if (!outSlot.linkIds.length) continue
      for (const linkId of outSlot.linkIds) {
        const resolved = LLink.resolve(linkId, graph)
        if (!resolved) continue
        const { link, inputNode, input } = resolved
        if (!inputNode || !input) continue
        const endPos = LiteGraph.vueNodesMode
          ? getSlotPosition(inputNode, link.target_slot, true)
          : inputNode.getInputPos(link.target_slot)
        testLink(
          link,
          outSlot.pos,
          endPos,
          input.dir ?? LinkDirection.LEFT,
          input.dir ?? LinkDirection.LEFT
        )
      }
    }

    for (const slot of subgraph.outputNode.slots) {
      if (!slot.linkIds.length) continue
      const resolved = LLink.resolve(slot.linkIds[0], graph)
      if (!resolved) continue
      const { link, outputNode, output } = resolved
      if (!outputNode || !output) continue
      const startPos = LiteGraph.vueNodesMode
        ? getSlotPosition(outputNode, link.origin_slot, false)
        : outputNode.getOutputPos(link.origin_slot)
      testLink(
        link,
        startPos,
        slot.pos,
        output.dir ?? LinkDirection.RIGHT,
        slot.dir ?? LinkDirection.LEFT
      )
    }
  }

  return ids
}

function collectCutIdsFromLayoutStoreLine(
  x1: number,
  y1: number,
  x2: number,
  y2: number
): Set<number> {
  const ids = new Set<number>()
  const canvas = app.canvas
  const ctx = canvas.ctx
  const oldW = ctx.lineWidth
  ctx.lineWidth = canvas.connections_width + 10
  try {
    for (let i = 0; i <= CUT_LINE_SAMPLES; i++) {
      const t = i / CUT_LINE_SAMPLES
      const px = x1 + (x2 - x1) * t
      const py = y1 + (y2 - y1) * t
      const hit = layoutStore.queryLinkSegmentAtPoint({ x: px, y: py }, ctx)
      if (hit) ids.add(hit.linkId)
    }
  } finally {
    ctx.lineWidth = oldW
  }
  return ids
}

function collectCutIdsFromRenderedPaths(
  canvas: LGraphCanvas,
  x1: number,
  y1: number,
  x2: number,
  y2: number
): Set<number> {
  const ids = new Set<number>()
  for (const seg of canvas.renderedPaths) {
    if (!seg.path) continue
    if (!lineHitsPath(canvas, seg.path, x1, y1, x2, y2)) continue
    if (seg instanceof LLink) {
      ids.add(Number(seg.id))
    } else if (seg instanceof Reroute) {
      for (const lid of seg.linkIds) ids.add(lid)
    }
  }
  return ids
}

/** Union of hit-test strategies; works for point (x1===x2, y1===y2) or line cuts. */
export function findLinkIdsForCutLine(
  x1: number,
  y1: number,
  x2: number,
  y2: number
): Set<number> {
  const canvas = app.canvas
  const a = collectCutIdsFromRenderedPaths(canvas, x1, y1, x2, y2)
  const b = collectCutIdsFromLayoutStoreLine(x1, y1, x2, y2)
  const c = collectCutIdsFromRebuiltSimpleLinks(canvas, x1, y1, x2, y2)
  return new Set([...a, ...b, ...c])
}

export function removeLinksByIds(linkIds: Set<number>): void {
  const g = app.canvas.graph
  if (!g || app.canvas.read_only || linkIds.size === 0) return
  for (const id of linkIds) {
    g.removeLink(id)
  }
  app.canvas.setDirty(false, true)
  // One undo step per removal batch (each scissors cut calls this once; multi-select delete once).
  useWorkflowStore().activeWorkflow?.changeTracker?.checkState()
}
